    fun getStructuredResponse(prompt: String, isEnglish: Boolean = false): AiStructuredResponse? {
        val q = prompt.lowercase()
        
        val key = when {
            // Package 15 prioritized triggers sitting at the absolute top
            q.contains("rejyonal anestezi") || q.contains("regional anesthesia") -> "anticoagulant_regional_block"
            q.contains("periferik sinir bloğu") || q.contains("periferik blok") || q.contains("peripheral nerve block") || q.contains("blok güvenlik") || q.contains("blok öncesi kontrol") || q.contains("pre block checklist") -> "regional_anesthesia_safety"
            q.contains("ultrason eşliğinde blok") || q.contains("iğne ucu") || q.contains("fraksiyone enjeksiyon") || q.contains("ultrasound guided block") || q.contains("needle tip") || q.contains("fractionated injection") -> "ultrasound_guided_block"
            q.contains("interskalen blok") || q.contains("frenik sinir") || q.contains("hemidiyafram") || q.contains("omuz bloğu") || q.contains("interscalene block") || q.contains("phrenic nerve") || q.contains("hemidiaphragm") || q.contains("shoulder block") -> "interscalene_block"
            q.contains("supraklaviküler blok") || q.contains("pnömotoraks blok") || q.contains("brakiyal pleksus") || q.contains("supraclavicular block") || q.contains("pneumothorax block") || q.contains("brachial plexus") -> "supraclavicular_block"
            q.contains("infraklaviküler blok") || q.contains("infraclavicular block") -> "infraclavicular_block"
            q.contains("aksiller blok") || q.contains("musculocutaneous sinir") || q.contains("axillary block") || q.contains("musculocutaneous nerve") -> "axillary_block"
